class Base {
public:
 int publicVar;
 void publicMethod() { }
protected:
 int protectedVar;
 void protectedMethod() { }
private:
 int privateVar;
 void privateMethod() { }
};

class DerivedPublic : public Base {
 void accessMembers() {
 publicVar = 10; // OK: public
 protectedVar = 20; // OK: protected accessible to derived
 // privateVar = 30; // ERROR: private not accessible
 }
};

// Outside access:
DerivedPublic obj;
obj.publicVar = 10; // OK
// obj.protectedVar = 20; // ERROR

class DerivedPrivate : private Base {
 void accessMembers() {
 publicVar = 10; // OK: but becomes private
 protectedVar = 20; // OK: but becomes private
 // privateVar = 30; // ERROR
 }
};

// Outside access:
DerivedPrivate obj;
// obj.publicVar = 10; // ERROR: now private
// obj.protectedVar = 20; // ERROR: now private

class DerivedProtected : protected Base {
 void accessMembers() {
 publicVar = 10; // OK: but becomes protected
 protectedVar = 20; // OK: stays protected
 // privateVar = 30; // ERROR
 }
};

class FurtherDerived : public DerivedProtected {
 void moreAccess() {
 publicVar = 10; // OK: still accessible as protected
 protectedVar = 20; // OK
 }
};

// Outside access:
DerivedProtected obj;
// obj.publicVar = 10; // ERROR: protected not accessible outside

class Base {
public:
 Base() { cout << "Base Constructor\n"; }
 ~Base() { cout << "Base Destructor\n"; }
};

class Derived : public Base {
public:
 Derived() { cout << "Derived Constructor\n"; }
 ~Derived() { cout << "Derived Destructor\n"; }
};

int main() {
 Derived obj;
 return 0;
}
// Output:
// Base Constructor
// Derived Constructor
// Derived Destructor
// Base Destructor

class Base {
public:
 void show() { cout << "Show\n"; }
protected:
 void display() { cout << "Display\n"; }
};

class Derived : private Base {
public:
 using Base::show; // Now public in Derived
 using Base::display; // Now public in Derived
};

int main() {
 Derived d;
 d.show(); // OK: accessible
 d.display(); // OK: accessible
 return 0;
}
